## Clara Tool - Transferir Humano v2

Remove tags IA, adiciona Qualificado + Transferido Humano, move pipeline.

**Input:** { phone, stage_id, resumo }
**Output:** { resultado, contact_id, sucesso }

parameters.jsCode:
// Validate input + unwrap $fromAI query fields
// n8n LangChain toolWorkflow puts $fromAI fields inside "query" object
// while static expressions stay at top level
const raw = $input.first().json;

// Merge query fields into top level
const query = raw.query || {};
const input = { ...raw };

// Unwrap query fields (AI-generated via $fromAI)
if (typeof query === 'object' && query !== null) {
  for (const [key, value] of Object.entries(query)) {
    if (key !== 'phone' && input[key] === undefined) {
      input[key] = value;
    }
  }
}
delete input.query;

// Validate phone
const phone = input.phone || '';
if (!phone || phone.trim() === '') {
  return [{ json: { resultado: 'Erro: telefone do lead não fornecido.', sucesso: false } }];
}

// Clean phone (remove non-digits, keep +)
input.phone = phone.replace(/[^\d+]/g, '');

return [{ json: input }];

parameters.jsonBody:
={{
(() => {
  const currentContact = $('GHL Buscar p/ Transferir').item.json.contact || {};
  const currentTags = currentContact.tags || [];
  const input = $('Validar Input').item.json;

  // Remove "Em Atendimento IA" and "Clara SDR", add "Qualificado" and "Transferido Humano"
  let tags = currentTags.filter(t =>
    t !== 'Em Atendimento IA' && t !== 'Clara SDR'
  );
  tags.push('Qualificado');
  tags.push('Transferido Humano');
  tags = [...new Set(tags)];

  const body = { tags };

  // Add resumo as note if provided
  if (input.resumo) {
    body.companyName = currentContact.companyName || '';
  }

  return JSON.stringify(body);
})()
}}

={{
(() => {
  const input = $('Validar Input').item.json;
  const body = {};

  // Move to next stage if provided
  if (input.stage_id) {
    body.pipelineStageId = input.stage_id;
  }

  // Add notes
  if (input.resumo) {
    body.name = input.resumo.substring(0, 100);
  }

  return JSON.stringify(body);
})()
}}

parameters.jsCode:
const contact = $('GHL Buscar p/ Transferir').item.json.contact || {};
const tagResult = $('GHL Tags Transferência').item.json;

let oppMoved = false;
try {
  const oppResult = $('GHL Mover Etapa').item.json;
  oppMoved = !!oppResult.opportunity;
} catch(e) {}

return [{ json: {
  resultado: "Lead transferido para atendimento humano com sucesso. Tags atualizadas: 'Qualificado' e 'Transferido Humano' adicionadas. Tag 'Em Atendimento IA' removida." + (oppMoved ? " Oportunidade movida para próxima etapa." : ""),
  contact_id: contact.id,
  sucesso: true
}}];

